from pathlib import Path

from omdlib.config_api import Config

_AUTHORISATION_PNP_CONTENT = """\
<?php
// Created by OMD hook MULTISITE_AUTHORISATION
// Use the permissions files generated by multisite
if(file_exists(OMD_SITE_ROOT.'/var/check_mk/wato/auth/auth.php')) {
    require_once(OMD_SITE_ROOT.'/var/check_mk/wato/auth/auth.php');

    // Before the first use of multisite the auth.php is empty and does not contain this
    // function. Do try to execute these functions in this case.
    if(function_exists('users_with_permission')) {
        $conf['allowed_for_all_services'] = implode(',', users_with_permission('general.see_all'));
        $conf['allowed_for_all_hosts'] = implode(',', users_with_permission('general.see_all'));
    }
}
?>
"""


def write_multisite_cookie_auth(site_name: str, site_home: Path, config: Config) -> None:
    apache_cfg = site_home / "etc" / "apache" / "conf.d" / "cookie_auth.conf"
    nagvis_cfg = site_home / "etc" / "nagvis" / "conf.d" / "cookie_auth.ini.php"
    if config["MULTISITE_COOKIE_AUTH"] == "on":
        with open(apache_cfg, "w") as f:
            f.write(
                f"""\
<LocationMatch ^/{site_name}/(nagvis|check_mk)>
    Order allow,deny
    Allow from all
    Satisfy any
</LocationMatch>
"""
            )
        if nagvis_cfg.parent.is_dir():
            with open(nagvis_cfg, "w") as f:
                f.write(
                    f"""\
[global]
logonmodule="LogonMultisite"
logon_multisite_htpasswd="/omd/sites/{site_name}/etc/htpasswd"
logon_multisite_secret="/omd/sites/{site_name}/etc/auth.secret"
logon_multisite_serials="/omd/sites/{site_name}/etc/auth.serials"
logon_multisite_cookie_version=1
"""
                )
    else:
        if apache_cfg.is_file():
            apache_cfg.unlink()
        if nagvis_cfg.is_file():
            nagvis_cfg.unlink()


def write_multisite_authorisation(_site_name: str, site_home: Path, config: Config) -> None:
    nagvis_cfg = site_home / "etc" / "nagvis" / "conf.d" / "authorisation.ini.php"
    pnp_cfg = site_home / "etc" / "pnp4nagios" / "config.d" / "authorisation.php"
    if config["MULTISITE_AUTHORISATION"] == "on":
        nagvis_cfg.parent.mkdir(parents=True, exist_ok=True)
        with open(nagvis_cfg, "w") as f:
            f.write(
                f"""\
; Created by OMD hook MULTISITE_AUTHORISATION
; Use the permissions files generated by multisite
[global]
authorisationmodule="CoreAuthorisationModMultisite"
authorisation_multisite_file="{site_home}/var/check_mk/wato/auth/auth.php"
"""
            )
        pnp_dir = pnp_cfg.parent
        if pnp_dir.parent.is_dir():
            pnp_dir.mkdir(exist_ok=True)
            with open(pnp_cfg, "w") as f:
                f.write(_AUTHORISATION_PNP_CONTENT)
    else:
        if nagvis_cfg.is_file():
            nagvis_cfg.unlink()
        if pnp_cfg.is_file():
            pnp_cfg.unlink()
